import React from "react";
import ResultCard from "./components/ResultCard";
import GoogleMap from "./components/GoogleMap";
import algoliasearch from "algoliasearch/lite";

import {
  InstantSearch,
  Hits,
  SearchBox,
  Pagination,
  MenuSelect,
  connectStateResults,
} from "react-instantsearch-dom";

const searchClient = algoliasearch(
  "ZCALIJLNAN",
  "d2274cd9dbdbed4d953cba839f078194"
);

const Results = connectStateResults(
  ({ searchResults, searchState, searchingForFacetValues }) =>
    searchState && searchState.query ? (
      <div>
        <small className="text-muted">
          Found {searchResults.nbHits} results for "{searchState.query}"
        </small>
        <Hits hitComponent={Hit} className="mt-3" />
        <div className="pagination mt-2 d-flex justify-content-center">
          {searchResults.nbHits > 8 && <Pagination />}
        </div>
      </div>
    ) : (
      <div>
        <small className="text-muted">
          Currently displaying top 8 by links
        </small>
        <Hits hitComponent={Hit} className="mt-3" />
      </div>
    )
);

const Hit = (props) => <ResultCard airport={props.hit} />;

export default function App() {
  return (
    <InstantSearch searchClient={searchClient} indexName="dev_airports">
      <div className="container-fluid mt-3">
        <div className="row">
          <div className="col-12">
            <div className="ct-page-title">
              <h1 className="ct-title" id="content">
                Airport Search
              </h1>
            </div>
            <SearchBox
              autoFocus="true"
              translations={{
                placeholder:
                  "Search for an airport (Airport Name, code, city, or country)",
              }}
            />
          </div>
        </div>
        <hr />
        <div className="row mt-2">
          <div className="col-lg-3 col-sm-5 col-xs-6">
            <h6>Filter</h6>
            <MenuSelect
              attribute="country"
              translations={{
                seeAllOption: "All countries",
              }}
            />
            <h6 className="mt-3">Results</h6>
            <Results />
          </div>
          <div className="col-lg-9 col-sm-7 col-xs-6">
            <GoogleMap></GoogleMap>
          </div>
        </div>
      </div>
    </InstantSearch>
  );
}
