import {
  GoogleMapsLoader,
  GeoSearch,
  Control,
  Marker,
} from "react-instantsearch-dom-maps";

export default function GoogleMap() {
  return (
    <div style={{ height: 600 }}>
      <GoogleMapsLoader apiKey="AIzaSyCvTFZNyU0jLWwcAnljNkfZLqx4zwCOLZQ">
        {(google) => (
          <GeoSearch google={google}>
            {({ hits }) => (
              <div>
                <Control />
                {hits.length > 0 &&
                  hits.map((hit) => (
                    <Marker key={hit.objectID} hit={hit}>
                      {hit.name}
                    </Marker>
                  ))}
                {""}
              </div>
            )}
          </GeoSearch>
        )}
      </GoogleMapsLoader>
    </div>
  );
}
